args.sqlite_command:
DROP TABLE IF EXISTS J09C_temp;
CREATE TABLE J09C_temp AS
SELECT *
FROM decision_table
WHERE TOUR LIKE 'J09C%';
ALTER TABLE J09C_temp ADD COLUMN ENTSCHEIDUNG TEXT;

WITH haus_counts AS (
  SELECT HAUS, COUNT(EQUNR) AS eq_count
  FROM J09C_temp
  GROUP BY HAUS
)
UPDATE J09C_temp
SET ENTSCHEIDUNG = CASE
  WHEN (SELECT eq_count FROM haus_counts WHERE haus_counts.HAUS = J09C_temp.HAUS) < 3 THEN 'KSA'
  ELSE 'EVU'
END;

UPDATE J09C_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 = 0;
UPDATE J09C_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 500 AND 599;
UPDATE J09C_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 900 AND 999;
UPDATE J09C_temp SET ENTSCHEIDUNG = 'EVU' WHERE CITY2 IN ('Wiblingwerde', 'Breckerfeld');

ALTER TABLE J09C_temp ADD COLUMN "Meter Reading (MR) Doc. No." TEXT;
ALTER TABLE J09C_temp ADD COLUMN TITLE TEXT;
ALTER TABLE J09C_temp ADD COLUMN FORENAME TEXT;
ALTER TABLE J09C_temp ADD COLUMN SURNAME TEXT;
ALTER TABLE J09C_temp ADD COLUMN STREET TEXT;
ALTER TABLE J09C_temp ADD COLUMN STREETNO TEXT;
ALTER TABLE J09C_temp ADD COLUMN final_CITY1 TEXT;
ALTER TABLE J09C_temp ADD COLUMN final_CITY2 TEXT;
ALTER TABLE J09C_temp ADD COLUMN final_POST_CODE1 INTEGER;
ALTER TABLE J09C_temp ADD COLUMN EMAIL TEXT;

UPDATE J09C_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT eablg."Meter Reading (MR) Doc. No."
  FROM eablg
  WHERE eablg.Installation = J09C_temp.ANLAGE
  LIMIT 1
);

UPDATE J09C_temp
SET 
  TITLE = COALESCE((SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  FORENAME = COALESCE((SELECT s.FORENAME FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.FORENAME FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  SURNAME = COALESCE((SELECT s.SURNAME FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.SURNAME FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  STREET = COALESCE((SELECT s.STREET FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.STREET FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  STREETNO = COALESCE((SELECT s.STREETNO FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.STREETNO FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  final_CITY1 = COALESCE((SELECT s.CITY1 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.CITY1 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  final_CITY2 = COALESCE((SELECT s.CITY2 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.CITY2 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  final_POST_CODE1 = COALESCE((SELECT s.POST_CODE1 FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.POST_CODE1 FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1)),
  EMAIL = COALESCE((SELECT s.EMAIL FROM sales_master s WHERE s.EQUNR = J09C_temp.EQUNR LIMIT 1), (SELECT n.EMAIL FROM net_master n WHERE n.EQUNR = J09C_temp.EQUNR LIMIT 1));

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2024'
  INTERSECT
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2023'
);
